import { describe, it, expect, afterEach } from 'vitest';
import { MeshRuntime } from './mesh-runtime.js';
import { MeshEventFanout } from './sse-fanout.js';
import { createMeshLocalMcpApp } from './main.js';

describe('mesh-local-mcp', () => {
  let close: (() => Promise<void>) | undefined;

  afterEach(async () => {
    if (close) await close();
    close = undefined;
  });

  it('serves /health + /mesh/status and streams normalized mesh events', async () => {
    const runtime = new MeshRuntime(process.cwd());
    const fanout = new MeshEventFanout();
    const { app, transports } = createMeshLocalMcpApp(runtime, fanout, '127.0.0.1');

    const server = await new Promise<import('node:http').Server>((resolvePromise, reject) => {
      const s = app.listen(0, '127.0.0.1', () => resolvePromise(s));
      s.on('error', reject);
    });
    const addr = server.address();
    if (!addr || typeof addr === 'string') throw new Error('expected tcp address');
    const port = addr.port;
    close = async () => {
      for (const t of Object.values(transports)) {
        await t.close().catch(() => undefined);
      }
      await new Promise<void>((res, rej) => server.close((e) => (e ? rej(e) : res())));
    };

    const health = await fetch(`http://127.0.0.1:${port}/health`);
    expect(health.ok).toBe(true);
    const body = (await health.json()) as { ok?: boolean };
    expect(body.ok).toBe(true);

    const status = await fetch(`http://127.0.0.1:${port}/mesh/status?limit=5`);
    expect(status.ok).toBe(true);
    const statusJson = (await status.json()) as { ok?: boolean; details?: { recentEvents?: unknown[] } };
    expect(statusJson.ok).toBe(true);
    expect(Array.isArray(statusJson.details?.recentEvents)).toBe(true);

    const es = await fetch(`http://127.0.0.1:${port}/mesh/events`);
    expect(es.ok).toBe(true);
    const reader = es.body?.getReader();
    if (!reader) throw new Error('no body');
    const dec = new TextDecoder();
    let acc = '';
    for (let i = 0; i < 20 && !acc.includes('mesh_events_ready'); i += 1) {
      const { value, done } = await reader.read();
      if (done) break;
      acc += dec.decode(value, { stream: true });
    }
    reader.cancel().catch(() => undefined);
    expect(acc).toContain('mesh_events_ready');
    expect(acc).toContain('eventType');
  });
});
